mapper.select:
select sum(original_power_consumption) original_power_consumption, sum(original_unit_power_consumption) original_unit_power_consumption, sum(original_operating_power) original_operating_power, sum(original_light_up_time) original_light_up_time, sum(original_carbon_emission) original_carbon_emission, sum(actual_power_consumption) actual_power_consumption, sum(actual_unit_power_consumption) actual_unit_power_consumption, sum(actual_operating_power) actual_operating_power, sum(actual_light_up_time) actual_light_up_time, sum(actualCarbonEmission) actualCarbonEmission from t_tunnel_statistics
AND DATE_FORMAT(upload_time,'%Y-%m-%d') >= #{startTime}
AND DATE_FORMAT(upload_time,'%Y-%m-%d') <= #{endTime}
and tunnel_id = #{tunnelId}








select date(upload_time) upload_time,
       sum(actualCarbonEmission) actualCarbonEmission,
       (sum(original_carbon_emission) - sum(actualCarbonEmission)) original_carbon_emission
from t_tunnel_statistics


        AND DATE_FORMAT(upload_time,'%Y-%m-%d') >= #{startTime}


        AND DATE_FORMAT(upload_time,'%Y-%m-%d') <= #{endTime}


        and tunnel_id in

            #{tunnelId}



group by date(upload_time) order by date(upload_time) desc

SELECT HOUR(upload_time) as hour,
sum(actual_power_consumption) as powerConsumption
FROM t_tunnel_statistics
WHERE DATE(upload_time) = CURDATE() and tunnel_id = #{tunnelId}
GROUP BY HOUR(upload_time) ORDER BY Hour(upload_time);

select MONTH(upload_time) `month`, (sum(original_power_consumption) - sum(actual_power_consumption)) totalEconomyLight, sum(actual_power_consumption) totalLight from t_tunnel_statistics
AND DATE_FORMAT(upload_time,'%Y')=#{year}
and tunnel_id in
#{tunnelId}
GROUP BY MONTH(upload_time)

SELECT COALESCE(SUM(cnt), 0) AS deviceCount, COALESCE(SUM(online_cnt), 0) AS deviceOnline FROM (
SELECT COUNT(DISTINCT td.device_id) AS cnt, COUNT(DISTINCT CASE WHEN COALESCE(td.Online, 0) = 1 THEN td.device_id END) AS online_cnt FROM tunnel_devicelist td INNER JOIN tunnel_devicelist_tunnelinfo tdi ON td.device_id = tdi.devicelist_id AND tdi.type IN (1, 2) WHERE td.device_type_id IN (1, 2)
AND tdi.tunnel_id IN #{tid}
AND 1 = 0
UNION ALL
SELECT COUNT(DISTINCT tor.id) AS cnt, COUNT(DISTINCT CASE WHEN tor.device_status = '00' THEN tor.id END) AS online_cnt FROM tunnel_out_of_radar tor INNER JOIN tunnel_devicelist_tunnelinfo tdi ON tor.devicelist_id = tdi.devicelist_id AND tdi.type = 1
AND tdi.tunnel_id IN #{tid}
AND 1 = 0
UNION ALL
SELECT COUNT(DISTINCT tlt.unique_id) AS cnt, COUNT(DISTINCT CASE WHEN tlt.lamps_status IS NOT NULL AND (tlt.lamps_status & 1) = 0 AND (tlt.lamps_status & 4) = 0 THEN tlt.unique_id END) AS online_cnt FROM tunnel_lamps_terminal tlt INNER JOIN tunnel_lamps_edge_computing tlec ON tlt.unique_id = tlec.unique_id INNER JOIN tunnel_devicelist_tunnelinfo tdi ON tlec.devicelist_id = tdi.devicelist_id AND tdi.type = 1
AND tdi.tunnel_id IN #{tid}
AND 1 = 0
) t
